    uint32_t tileN = BASE_TILE_N;
    uint32_t tileK = MAX_TILE_K;

    if (M < tileM) tileM = M;
    if (N < tileN) tileN = N;
    if (K < tileK) tileK = K;

    tileK = AlignDown(tileK, ALIGN_K);
    if (tileK == 0) tileK = (K > 0 ? K : 1);

    // Fit memory budget by shrinking tileK, then tileN, then tileM if needed
    auto MemUsageBytes = [&](uint32_t tm, uint32_t tn, uint32_t tk)->uint64_t {
        uint64_t xbuf = static_cast<uint64_t>(tm) * tk;
        uint64_t wbuf = static_cast<uint64_t>(tn) * tk;
        uint64_t acc  = static_cast<uint64_t>(tm) * tn;
        uint64_t tmp  = tk;
        uint64_t bs   = tn;
        return (xbuf + wbuf + acc + tmp + bs) * sizeof(float);
