kernel_src="""

#include "kernel_operator.h"

constexpr int32_t BUFFER_NUM = 1;

class KernelGemmAddReluCustom {
public:
    __aicore__ inline KernelGemmAddReluCustom() {}

    __aicore__ inline void Init(GM_ADDR x, GM_ADDR w, GM_ADDR bias, GM_ADDR y,
                                uint32_t M, uint32_t N, uint32_t K,
                                uint32_t tileM, uint32_t tileN, uint32_t tileK,
                                uint32_t numTilesM, uint32_t numTilesN)
    {
        M_ = M; N_ = N; K_ = K;
        tM_ = tileM; tN_ = tileN; tK_ = tileK;
        nTilesM_ = numTilesM; nTilesN_ = numTilesN;
        totalTiles_ = nTilesM_ * nTilesN_;

        xGm_.SetGlobalBuffer((__gm__ float*)x, static_cast<uint64_t>(M_) * K_);
        wGm_.SetGlobalBuffer((__gm__ float*)w, static_cast<uint64_t>(N_) * K_);
        bGm_.SetGlobalBuffer((__gm__ float*)bias, N_);
        yGm_.SetGlobalBuffer((__gm__ float*)y, static_cast<uint64_t>(M_) * N_);

        // Buffers: xTile (tM_*tK_), wTile (tN_*tK_), acc (tM_*tN_), tmp (tK_), bias (tN_)
        pipe_.InitBuffer(xQueue_, BUFFER_NUM, tM_ * tK_ * sizeof(float));
        pipe_.InitBuffer(wQueue_, BUFFER_NUM, tN_ * tK_ * sizeof(float));
        pipe_.InitBuffer(accQueue_, BUFFER_NUM, tM_ * tN_ * sizeof(float));
        pipe_.InitBuffer(tmpQueue_, BUFFER_NUM, tK_ * sizeof(float));
        pipe_.InitBuffer(biasQueue_, BUFFER_NUM, tN_ * sizeof(float));
    }

    __aicore__ inline void Process()
    {
        if (M_ == 0 || N_ == 0 || K_ == 0) {
            return;
        }

        const uint32_t blockNum = static_cast<uint32_t>(AscendC::GetBlockNum());
        const uint32_t blockIdx = static_cast<uint32_t>(AscendC::GetBlockIdx());

        // Grid-stride over output tiles
        for (uint32_t tileIndex = blockIdx; tileIndex < totalTiles_; tileIndex += blockNum) {
            const uint32_t tileRow = tileIndex / nTilesN_;
            const uint32_t tileCol = tileIndex % nTilesN_;
            const uint32_t rowStart = tileRow * tM_;
            const uint32_t colStart = tileCol * tN_;
            const uint32_t mRange = (rowStart + tM_ <= M_) ? tM_ : (M_ - rowStart);
            const uint32_t nRange = (colStart + tN_ <= N_) ? tN_ : (N_ - colStart);

            ComputeTile(rowStart, colStart, mRange, nRange);
        }
    }

private:
    __aicore__ inline void ZeroAcc(AscendC::LocalTensor<float>& acc, uint32_t count)
    {
        // acc = 0
        AscendC::Muls(acc, acc, 0.0f, count);
    }

    __aicore__ inline void CopyXSub(AscendC::LocalTensor<float>& xLocal,
                                    uint32_t rowStart, uint32_t kStart, uint32_t mRange, uint32_t stepLen)
    {
        // Layout xLocal as [tM_ x tK_], write each row to base = i*tK_
        for (uint32_t i = 0; i < mRange; ++i) {
            const uint64_t gmOff = static_cast<uint64_t>(rowStart + i) * K_ + kStart;
            AscendC::DataCopy(xLocal[i * tK_], xGm_[gmOff], stepLen);
        }
    }

    __aicore__ inline void CopyWSub(AscendC::LocalTensor<float>& wLocal,
                                    uint32_t colStart, uint32_t kStart, uint32_t nRange, uint32_t stepLen)
    {
        // Layout wLocal as [tN_ x tK_], write each row (out channel) to base = j*tK_
        for (uint32_t j = 0; j < nRange; ++j) {
            const uint64_t gmOff = static_cast<uint64_t>(colStart + j) * K_ + kStart;
            AscendC::DataCopy(wLocal[j * tK_], wGm_[gmOff], stepLen);
        }
    }

    __aicore__ inline void CopyBias(AscendC::LocalTensor<float>& bLocal, uint32_t colStart, uint32_t nRange)
    {
        AscendC::DataCopy(bLocal, bGm_[colStart], nRange);
    }

    __aicore__ inline void ReduceSumInplace(AscendC::LocalTensor<float>& tmp, uint32_t len)
    {
        // In-place tree reduction: tmp[0] will hold the sum
        uint32_t cur = len;
        while (cur > 1) {
            uint32_t half = cur >> 1; // floor(cur/2)
            AscendC::Add(tmp, tmp, tmp[half], half);
            if ((cur & 1u) != 0u) {
                AscendC::Add(tmp, tmp, tmp[(half << 1)], 1);
            }
            cur = half;
        }
    }

    __aicore__ inline void ComputeTile(uint32_t rowStart, uint32_t colStart, uint32_t mRange, uint32_t nRange)
    {
        AscendC::LocalTensor<float> xLocal = xQueue_.AllocTensor<float>();
        AscendC::LocalTensor<float> wLocal = wQueue_.AllocTensor<float>();
        AscendC::LocalTensor<float> accLocal = accQueue_.AllocTensor<float>();
        AscendC::LocalTensor<float> tmpLocal = tmpQueue_.AllocTensor<float>();
        AscendC::LocalTensor<float> bLocal = biasQueue_.AllocTensor<float>();

        const uint32_t accCount = tM_ * tN_;
        ZeroAcc(accLocal, accCount);

        for (uint32_t k0 = 0; k0 < K_; k0 += tK_) {
            const uint32_t stepLen = ((k0 + tK_) <= K_) ? tK_ : (K_ - k0);
            if (stepLen == 0) break;

            CopyXSub(xLocal, rowStart, k0, mRange, stepLen);
            CopyWSub(wLocal, colStart, k0, nRange, stepLen);

            for (uint32_t i = 0; i < mRange; ++i) {
                // x row base
                AscendC::LocalTensor<float> xRow = xLocal[i * tK_];
                for (uint32_t j = 0; j < nRange; ++j) {
                    AscendC::LocalTensor<float> wRow = wLocal[j * tK_];

                    // tmp = xRow * wRow
                    AscendC::Mul(tmpLocal, xRow, wRow, stepLen);
                    // reduce tmp to single element (at tmp[0])
                    ReduceSumInplace(tmpLocal, stepLen);
                    // acc[i, j] += tmp[0]
                    const uint32_t accOff = i * tN_ + j;
                    AscendC::Add(accLocal[accOff], accLocal[accOff], tmpLocal, 1);
                }
            }
        }

        // Add bias and ReLU, then store to GM
        CopyBias(bLocal, colStart, nRange);
        for (uint32_t i = 0; i < mRange; ++i) {
            AscendC::LocalTensor<float> yRow = accLocal[i * tN_];
            AscendC::Add(yRow, yRow, bLocal, nRange);
            AscendC::Maxs(yRow, yRow, 0.0f, nRange);

            const uint64_t yOff = static_cast<uint64_t>(rowStart + i) * N_ + colStart;
            AscendC::DataCopy(yGm_[yOff], yRow, nRange);
        }

        biasQueue_.FreeTensor(bLocal);
        tmpQueue_.FreeTensor(tmpLocal);
        accQueue_.FreeTensor(accLocal);
        wQueue_.FreeTensor(wLocal);
        xQueue_.FreeTensor(xLocal);
    }

private:
    AscendC::TPipe pipe_;
    AscendC::TQue<AscendC::TPosition::VECIN, BUFFER_NUM> xQueue_;
    AscendC::TQue<AscendC::TPosition::VECIN, BUFFER_NUM> wQueue_;
    AscendC::TQue<AscendC::TPosition::VECCALC, BUFFER_NUM> accQueue_;
    AscendC::TQue<AscendC::TPosition::VECCALC, BUFFER_NUM> tmpQueue_;
    AscendC::TQue<AscendC::TPosition::VECIN, BUFFER_NUM> biasQueue_;

    AscendC::GlobalTensor<float> xGm_;
    AscendC::GlobalTensor<float> wGm_;
    AscendC::GlobalTensor<float> bGm_;
    AscendC::GlobalTensor<float> yGm_;

    uint32_t M_{0}, N_{0}, K_{0};
    uint32_t tM_{0}, tN_{0}, tK_{0};
    uint32_t nTilesM_{0}, nTilesN_{0}, totalTiles_{0};
};

extern "C" __global__ __aicore__ void gemm_add_relu_custom(GM_ADDR x, GM_ADDR w, GM_ADDR bias, GM_ADDR y, GM_ADDR workspace, GM_ADDR tiling)
{
    GET_TILING_DATA(tiling_data, tiling);
    KernelGemmAddReluCustom op;
    op.Init(x, w, bias, y,
            tiling_data.M, tiling_data.N, tiling_data.K,
            tiling_data.tileM, tiling_data.tileN, tiling_data.tileK,
            tiling_data.numTilesM, tiling_data.numTilesN);
    op.Process();
}
